-- Cosmetic Functions Hebrew: Create table and insert 20 rows
CREATE TABLE IF NOT EXISTS cosmetic_functions_he (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  function_en TEXT NOT NULL,
  function_he TEXT DEFAULT '',
  consumer_desc_he TEXT DEFAULT '',
  consumer_desc_he_alt TEXT DEFAULT '',
  inci_examples TEXT DEFAULT '',
  inci_examples_he TEXT DEFAULT '',
  app_display_category TEXT DEFAULT '',
  created_at TEXT DEFAULT (datetime('now'))
);
